import React from 'react';

function Deck() {
    return(
        <div className="card">
            <button>Create Deck</button>
            <h2>{/* deck name */}</h2>
            <p>{/* card count */}</p>
            <h4>{/** deck description */}</h4>
            <button>View</button>
            <button>Study</button>
        </div>
    )
}

export default Deck;
